/**
 * Return merged product list: catalog base products + any admin DB overrides/additions.
 * Admin products with is_override=1 replace catalog entries with the same code.
 * Admin products with is_override=0 are additions (new products not in catalog).
 */
function get_merged_products() {
    $catalog = get_catalog_products();
    try {
        $adminProds = get_admin_products();
    } catch (Exception $e) {
        return $catalog; // DB not yet set up — return catalog as-is
    }

    // Index catalog by id for override lookup
    $catIndex = [];
    foreach ($catalog as $i => $p) {
        $catIndex[$p['id']] = $i;
    }

    $additions = [];
    foreach ($adminProds as $ap) {
        if (!empty($ap['is_override']) && isset($catIndex[$ap['prod_id']])) {
            // Override existing catalog entry
            $catalog[$catIndex[$ap['prod_id']]] = array_merge($catalog[$catIndex[$ap['prod_id']]], $ap);
        } else {
            // New product — add to list
            if (!empty($ap['is_active'])) {
                $additions[] = $ap;
            }
        }
    }

    return array_merge($catalog, $additions);
}
